from kafka import KafkaConsumer
import json

def process_transaction(transaction):
    # Here you can add the business logic for processing the transaction
    print(f"Processing transaction: {transaction}")

def message_handler(message_value):
    try:
        transaction = json.loads(message_value)
        process_transaction(transaction)
    except Exception as e:
        print(f"Error processing message: {e}")

consumer = KafkaConsumer(
    'financial_transactions',
    bootstrap_servers=['localhost:9092'],
    auto_offset_reset='earliest',
    enable_auto_commit=True,
    group_id='transaction_processor_group',
    value_deserializer=lambda x: x.decode('utf-8')
)

for message in consumer:
    message_handler(message.value)